import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

// Monitor liquidation events on a lending protocol
async function getLiquidationEvents(chainName, protocolAddress) {
  const resp = await client.BaseService.getLogEventsByAddress(
    chainName, protocolAddress, { startingBlock: "latest" }
  );
  return (resp.data?.items ?? []).filter(e =>
    e.decoded?.name === "Liquidation" || e.decoded?.name === "LiquidateBorrow"
  );
}
